module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);

    reg [63:0] adda_reg, addb_reg;
    reg i_en_reg;

    reg [63:0] carry_reg;

    reg [64:0] result_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'b0;
            addb_reg <= 64'b0;
            i_en_reg <= 1'b0;
            carry_reg <= 64'b0;
            result_reg <= 65'b0;
            o_en <= 1'b0;
        end
        else begin
            adda_reg <= adda;
            addb_reg <= addb;
            i_en_reg <= i_en;
            carry_reg[0] <= 1'b0;
            for (int i = 0; i < 64; i++) begin
                {carry_reg[i+1], result_reg[i]} <= adda_reg[i] + addb_reg[i] + carry_reg[i];
            end
            result_reg[64] <= carry_reg[64];
            o_en <= i_en_reg;
            result <= result_reg;
        end
    end

endmodule
